// MARK: - Services/KeychainService.swift

import Foundation
import Security

final class KeychainService {
    static let shared = KeychainService()
    
    private let service = "com.cryptowallet.keys"
    
    private init() {}
    
    func storePrivateKey(_ privateKeyData: Data, forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecValueData as String: privateKeyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeychainError.unableToStore(status)
        }
    }
    
    func retrievePrivateKey(forAddress address: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw KeychainError.unableToRetrieve(status)
        }
        
        return data
    }
    
    func deletePrivateKey(forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unableToDelete(status)
        }
    }
    
    enum KeychainError: LocalizedError {
        case unableToStore(OSStatus)
        case unableToRetrieve(OSStatus)
        case unableToDelete(OSStatus)
        
        var errorDescription: String? {
            switch self {
            case .unableToStore(let status):
                return "Unable to store key: \(status)"
            case .unableToRetrieve(let status):
                return "Unable to retrieve key: \(status)"
            case .unableToDelete(let status):
                return "Unable to delete key: \(status)"
            }
        }
    }
}

// MARK: - Services/CryptoService.swift

import Foundation
import CryptoKit
import CommonCrypto

final class CryptoService {
    static let shared = CryptoService()
    
    private init() {}
    
    // MARK: - Key Generation
    
    struct KeyPair {
        let privateKey: Data
        let publicKey: Data
        let address: String
    }
    
    func generateKeyPair() throws -> KeyPair {
        let privateKey = P256.Signing.PrivateKey()
        let privateKeyData = privateKey.rawRepresentation
        
        // For Ethereum-like addresses, we use secp256k1 in production.
        // Using P256 as a stand-in; in production, use a secp256k1 library.
        let publicKeyData = privateKey.publicKey.rawRepresentation
        
        let address = try deriveAddress(from: publicKeyData)
        
        return KeyPair(
            privateKey: privateKeyData,
            publicKey: publicKeyData,
            address: address
        )
    }
    
    func generateMnemonic() -> [String] {
        let wordList = BIP39WordList.english
        var entropy = Data(count: 16) // 128 bits = 12 words
        _ = entropy.withUnsafeMutableBytes { SecRandomCopyBytes(kSecRandomDefault, 16, $0.baseAddress!) }
        
        let hash = SHA256.hash(data: entropy)
        let hashByte = Array(hash)[0]
        let checksumBits = hashByte >> 4 // Take first 4 bits for 128-bit entropy
        
        var bits = ""
        for byte in entropy {
            bits += String(byte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        }
        bits += String(checksumBits, radix: 2).leftPadded(toLength: 4, withPad: "0")
        
        var words: [String] = []
        for i in 0..<12 {
            let start = bits.index(bits.startIndex, offsetBy: i * 11)
            let end = bits.index(start, offsetBy: 11)
            let indexStr = String(bits[start..<end])
            if let index = Int(indexStr, radix: 2), index < wordList.count {
                words.append(wordList[index])
            }
        }
        
        return words
    }
    
    func keyPairFromMnemonic(_ mnemonic: [String]) throws -> KeyPair {
        let mnemonicString = mnemonic.joined(separator: " ")
        let salt = "mnemonic"
        
        let seedData = try pbkdf2(
            password: mnemonicString,
            salt: salt,
            iterations: 2048,
            keyLength: 64
        )
        
        let privateKeyData = seedData.prefix(32)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = try deriveAddress(from: publicKeyData)
        
        return KeyPair(
            privateKey: Data(privateKeyData),
            publicKey: publicKeyData,
            address: address
        )
    }
    
    // MARK: - Address Derivation
    
    private func deriveAddress(from publicKey: Data) throws -> String {
        let hash = SHA256.hash(data: publicKey)
        let hashData = Data(hash)
        let addressBytes = hashData.suffix(20)
        let address = "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
        return address
    }
    
    // MARK: - Transaction Signing
    
    func signTransaction(_ transaction: UnsignedTransaction, privateKeyData: Data) throws -> Data {
        let encodedTx = try rlpEncode(transaction: transaction)
        let txHash = SHA256.hash(data: encodedTx)
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: Data(txHash))
        
        let signedTx = try rlpEncodeSignedTransaction(
            transaction: transaction,
            signature: signature.rawRepresentation
        )
        
        return signedTx
    }
    
    func signMessage(_ message: Data, privateKeyData: Data) throws -> Data {
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        var prefixedMessage = Data(prefix.utf8)
        prefixedMessage.append(message)
        
        let hash = SHA256.hash(data: prefixedMessage)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: Data(hash))
        
        return signature.rawRepresentation
    }
    
    // MARK: - RLP Encoding
    
    func rlpEncode(transaction: UnsignedTransaction) throws -> Data {
        var items: [RLPItem] = []
        items.append(.integer(transaction.nonce))
        items.append(.bigInteger(transaction.gasPrice))
        items.append(.bigInteger(transaction.gasLimit))
        items.append(.bytes(Data(hex: transaction.to)))
        items.append(.bigInteger(transaction.valueWei))
        items.append(.bytes(transaction.data))
        items.append(.integer(transaction.chainId))
        items.append(.integer(0)) // EIP-155 v
        items.append(.integer(0)) // EIP-155 r
        
        return RLPEncoder.encode(.list(items))
    }
    
    func rlpEncodeSignedTransaction(transaction: UnsignedTransaction, signature: Data) throws -> Data {
        let r = signature.prefix(32)
        let s = signature.suffix(from: 32).prefix(32)
        let v = transaction.chainId * 2 + 35
        
        var items: [RLPItem] = []
        items.append(.integer(transaction.nonce))
        items.append(.bigInteger(transaction.gasPrice))
        items.append(.bigInteger(transaction.gasLimit))
        items.append(.bytes(Data(hex: transaction.to)))
        items.append(.bigInteger(transaction.valueWei))
        items.append(.bytes(transaction.data))
        items.append(.integer(v))
        items.append(.bytes(r))
        items.append(.bytes(s))
        
        return RLPEncoder.encode(.list(items))
    }
    
    // MARK: - PBKDF2
    
    private func pbkdf2(password: String, salt: String, iterations: Int, keyLength: Int) throws -> Data {
        let passwordData = Data(password.utf8)
        let saltData = Data(salt.utf8)
        
        var derivedKey = Data(count: keyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            passwordData.withUnsafeBytes { passwordBytes in
                saltData.withUnsafeBytes { saltBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        saltData.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        UInt32(iterations),
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else {
            throw CryptoError.pbkdf2Failed
        }
        
        return derivedKey
    }
    
    enum CryptoError: LocalizedError {
        case invalidPrivateKey
        case signingFailed
        case pbkdf2Failed
        case invalidMnemonic
        
        var errorDescription: String? {
            switch self {
            case .invalidPrivateKey: return "Invalid private key"
            case .signingFailed: return "Transaction signing failed"
            case .pbkdf2Failed: return "Key derivation failed"
            case .invalidMnemonic: return "Invalid mnemonic phrase"
            }
        }
    }
}

// MARK: - RLP Encoding Support

enum RLPItem {
    case bytes(Data)
    case integer(Int)
    case bigInteger(String)
    case list([RLPItem])
}

struct RLPEncoder {
    static func encode(_ item: RLPItem) -> Data {
        switch item {
        case .bytes(let data):
            return encodeBytes(data)
        case .integer(let value):
            if value == 0 {
                return encodeBytes(Data())
            }
            return encodeBytes(intToData(value))
        case .bigInteger(let value):
            if let intValue = Int(value), intValue == 0 {
                return encodeBytes(Data())
            }
            return encodeBytes(bigIntToData(value))
        case .list(let items):
            var payload = Data()
            for item in items {
                payload.append(encode(item))
            }
            return encodeLength(payload.count, offset: 0xc0) + payload
        }
    }
    
    private static func encodeBytes(_ data: Data) -> Data {
        if data.count == 1 && data[0] < 0x80 {
            return data
        }
        return encodeLength(data.count, offset: 0x80) + data
    }
    
    private static func encodeLength(_ length: Int, offset: Int) -> Data {
        if length < 56 {
            return Data([UInt8(length + offset)])
        }
        let lengthData = intToData(length)
        return Data([UInt8(lengthData.count + offset + 55)]) + lengthData
    }
    
    private static func intToData(_ value: Int) -> Data {
        if value == 0 { return Data() }
        var v = value
        var bytes: [UInt8] = []
        while v > 0 {
            bytes.insert(UInt8(v & 0xff), at: 0)
            v >>= 8
        }
        return Data(bytes)
    }
    
    private static func bigIntToData(_ value: String) -> Data {
        guard let intValue = UInt64(value) else { return Data() }
        if intValue == 0 { return Data() }
        var v = intValue
        var bytes: [UInt8] = []
        while v > 0 {
            bytes.insert(UInt8(v & 0xff), at: 0)
            v >>= 8
        }
        return Data(bytes)
    }
}

// MARK: - Services/BlockchainService.swift

import Foundation

final class BlockchainService {
    static let shared = BlockchainService()
    
    private let session: URLSession
    private var rpcURL: URL
    private var chainId: Int
    
    // Network configuration
    enum Network {
        case mainnet
        case goerli
        case sepolia
        case custom(url: String, chainId: Int)
        
        var rpcURL: URL {
            switch self {
            case .mainnet:
                return URL(string: "https://mainnet.infura.io/v3/YOUR_INFURA_KEY")!
            case .goerli:
                return URL(string: "https://goerli.infura.io/v3/YOUR_INFURA_KEY")!
            case .sepolia:
                return URL(string: "https://sepolia.infura.io/v3/YOUR_INFURA_KEY")!
            case .custom(let url, _):
                return URL(string: url)!
            }
        }
        
        var chainId: Int {
            switch self {
            case .mainnet: return 1
            case .goerli: return 5
            case .sepolia: return 11155111
            case .custom(_, let id): return id
            }
        }
    }
    
    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: config)
        let network = Network.sepolia
        self.rpcURL = network.rpcURL
        self.chainId = network.chainId
    }
    
    func configure(network: Network) {
        self.rpcURL = network.rpcURL
        self.chainId = network.chainId
    }
    
    // MARK: - JSON-RPC Methods
    
    func getBalance(address: String) async throws -> String {
        let params: [Any] = [address, "latest"]
        let result: String = try await jsonRPCCall(method: "eth_getBalance", params: params)
        return hexToDecimalString(result)
    }
    
    func getTransactionCount(address: String) async throws -> Int {
        let params: [Any] = [address, "latest"]
        let result: String = try await jsonRPCCall(method: "eth_getTransactionCount", params: params)
        return hexToInt(result)
    }
    
    func getGasPrice() async throws -> String {
        let result: String = try await jsonRPCCall(method: "eth_gasPrice", params: [])
        return hexToDecimalString(result)
    }
    
    func estimateGas(from: String, to: String, value: String) async throws -> String {
        let txObject: [String: String] = [
            "from": from,
            "to": to,
            "value": "0x" + decimalToHex(value)
        ]
        let params: [Any] = [txObject]
        let result: String = try await jsonRPCCall(method: "eth_estimateGas", params: params)
        return hexToDecimalString(result)
    }
    
    func sendRawTransaction(_ signedTxData: Data) async throws -> String {
        let hexTx = "0x" + signedTxData.map { String(format: "%02x", $0) }.joined()
        let params: [Any] = [hexTx]
        let result: String = try await jsonRPCCall(method: "eth_sendRawTransaction", params: params)
        return result
    }
    
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt? {
        let params: [Any] = [txHash]
        
        struct RPCRequest: Encodable {
            let jsonrpc = "2.0"
            let method: String
            let params: [String]
            let id: Int = 1
        }
        
        let request = RPCRequest(method: "eth_getTransactionReceipt", params: [txHash])
        var urlRequest = URLRequest(url: rpcURL)
        urlRequest.httpMethod = "POST"
        urlRequest.addValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.httpBody = try JSONEncoder().encode(request)
        
        let (data, _) = try await session.data(for: urlRequest)
        
        struct RPCResponse: Decodable {
            let result: TransactionReceipt?
        }
        
        let response = try JSONDecoder().decode(RPCResponse.self, from: data)
        return response.result
    }
    
    func getBlockNumber() async throws -> Int {
        let result: String = try await jsonRPCCall(method: "eth_blockNumber", params: [])
        return hexToInt(result)
    }
    
    var currentChainId: Int { chainId }
    
    // MARK: - Private Helpers
    
    private func jsonRPCCall<T: Decodable>(method: String, params: [Any]) async throws -> T {
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": method,
            "params": params,
            "id": 1
        ]
        
        var request = URLRequest(url: rpcURL)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.httpError
        }
        
        struct RPCResponse<R: Decodable>: Decodable {
            let result: R?
            let error: RPCError?
        }
        
        struct RPCError: Decodable {
            let code: Int
            let message: String
        }
        
        let rpcResponse = try JSONDecoder().decode(RPCResponse<T>.self, from: data)
        
        if let error = rpcResponse.error {
            throw BlockchainError.rpcError(error.message)
        }
        
        guard let result = rpcResponse.result else {
            throw BlockchainError.emptyResponse
        }
        
        return result
    }
    
    private func hexToDecimalString(_ hex: String) -> String {
        let cleanHex = hex.hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        guard let value = UInt64(cleanHex, radix: 16) else { return "0" }
        return String(value)
    }
    
    private func hexToInt(_ hex: String) -> Int {
        let cleanHex = hex.hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        return Int(cleanHex, radix: 16) ?? 0
    }
    
    private func decimalToHex(_ decimal: String) -> String {
        guard let value = UInt64(decimal) else { return "0" }
        return String(value, radix: 16)
    }
    
    enum BlockchainError: LocalizedError {
        case httpError
        case rpcError(String)
        case emptyResponse
        case invalidResponse
        
        var errorDescription: String? {
            switch self {
            case .httpError: return "HTTP request failed"
            case .rpcError(let msg): return "RPC Error: \(msg)"
            case .emptyResponse: return "Empty response from node"
            case .invalidResponse: return "Invalid response format"
            }
        }
    }
}

struct TransactionReceipt: Decodable {
    let transactionHash: String
    let blockNumber: String
    let status: String
    let gasUsed: String
    
    var isSuccess: Bool {
        return status == "0x1"
    }
}

// MARK: - Services/WalletManager.swift

import Foundation
import SwiftUI

@MainActor
final class WalletManager: ObservableObject {
    @Published var wallets: [Wallet] = []
    @Published var selectedWallet: Wallet?
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var error: String?
    @Published var mnemonic: [String]?
    
    private let cryptoService = CryptoService.shared
    private let keychainService = KeychainService.shared
    private let blockchainService = BlockchainService.shared
    
    private let walletsKey = "stored_wallets"
    private let transactionsKey = "stored_transactions"
    
    init() {
        loadWallets()
        loadTransactions()
    }
    
    // MARK: - Wallet Management
    
    func createWallet(name: String) async {
        isLoading = true
        error = nil
        
        do {
            let mnemonic = cryptoService.generateMnemonic()
            self.mnemonic = mnemonic
            
            let keyPair = try cryptoService.keyPairFromMnemonic(mnemonic)
            
            try keychainService.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
            
            let wallet = Wallet(
                id: UUID(),
                address: keyPair.address,
                createdAt: Date(),
                name: name,
                balanceWei: "0"
            )
            
            wallets.append(wallet)
            selectedWallet = wallet
            saveWallets()
            
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func importWallet(mnemonic: [String], name: String) async {
        isLoading = true
        error = nil
        
        do {
            let keyPair = try cryptoService.keyPairFromMnemonic(mnemonic)
            
            try keychainService.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
            
            let wallet = Wallet(
                id: UUID(),
                address: keyPair.address,
                createdAt: Date(),
                name: name,
                balanceWei: "0"
            )
            
            wallets.append(wallet)
            selectedWallet = wallet
            saveWallets()
            
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func importWalletFromPrivateKey(_ privateKeyHex: String, name: String) async {
        isLoading = true
        error = nil
        
        do {
            let cleanHex = privateKeyHex.hasPrefix("0x") ? String(privateKeyHex.dropFirst(2)) : privateKeyHex
            guard let privateKeyData = Data(hex: cleanHex) else {
                throw WalletError.invalidPrivateKey
                return
            }
            
            let keyPair = try cryptoService.generateKeyPair()
            // In production, derive address from the imported private key
            
            try keychainService.storePrivateKey(privateKeyData, forAddress: keyPair.address)
            
            let wallet = Wallet(
                id: UUID(),
                address: keyPair.address,
                createdAt: Date(),
                name: name,
                balanceWei: "0"
            )
            
            wallets.append(wallet)
            selectedWallet = wallet
            saveWallets()
            
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func deleteWallet(_ wallet: Wallet) {
        do {
            try keychainService.deletePrivateKey(forAddress: wallet.address)
            wallets.removeAll { $0.id == wallet.id }
            if selectedWallet?.id == wallet.id {
                selectedWallet = wallets.first
            }
            saveWallets()
        } catch {
            self.error = error.localizedDescription
        }
    }
    
    // MARK: - Balance & Refresh
    
    func refreshBalance() async {
        guard let wallet = selectedWallet else { return }
        isLoading = true
        
        do {
            let balance = try await blockchainService.getBalance(address: wallet.address)
            if let index = wallets.firstIndex(where: { $0.id == wallet.id }) {
                wallets[index].balanceWei = balance
                selectedWallet = wallets[index]
                saveWallets()
            }
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func refreshAllBalances() async {
        isLoading = true
        
        for i in wallets.indices {
            do {
                let balance = try await blockchainService.getBalance(address: wallets[i].address)
                wallets[i].balanceWei = balance
            } catch {
                // Continue with other wallets
            }
        }
        
        if let selected = selectedWallet,
           let updated = wallets.first(where: { $0.id == selected.id }) {
            selectedWallet = updated
        }
        
        saveWallets()
        isLoading = false
    }
    
    // MARK: - Transaction Handling
    
    func sendTransaction(to: String, amountETH: Double) async -> String? {
        guard let wallet = selectedWallet else {
            error = "No wallet selected"
            return nil
        }
        
        isLoading = true
        error = nil
        
        do {
            let privateKeyData = try keychainService.retrievePrivateKey(forAddress: wallet.address)
            
            let nonce = try await blockchainService.getTransactionCount(address: wallet.address)
            let gasPrice = try await blockchainService.getGasPrice()
            let weiAmount = String(UInt64(amountETH * 1_000_000_000_000_000_000))
            
            let gasLimit: String
            do {
                gasLimit = try await blockchainService.estimateGas(from: wallet.address, to: to, value: weiAmount)
            } catch {
                gasLimit = "21000"
            }
            
            let unsignedTx = UnsignedTransaction(
                to: to,
                valueWei: weiAmount,
                gasPrice: gasPrice,
                gasLimit: gasLimit,
                nonce: nonce,
                chainId: blockchainService.currentChainId,
                data: Data()
            )
            
            let signedTx = try cryptoService.signTransaction(unsignedTx, privateKeyData: privateKeyData)
            let txHash = try await blockchainService.sendRawTransaction(signedTx)
            
            let transaction = Transaction(
                id: UUID(),
                from: wallet.address,
                to: to,
                valueWei: weiAmount,
                gasPrice: gasPrice,
                gasLimit: gasLimit,
                nonce: nonce,
                chainId: blockchainService.currentChainId,
                hash: txHash,
                timestamp: Date(),
                status: .pending
            )
            
            transactions.insert(transaction, at: 0)
            saveTransactions()
            
            isLoading = false
            return txHash
            
        } catch {
            self.error = error.localizedDescription
            isLoading = false
            return nil
        }
    }
    
    func signMessage(_ message: String) async -> Data? {
        guard let wallet = selectedWallet else {
            error = "No wallet selected"
            return nil
        }
        
        do {
            let privateKeyData = try keychainService.retrievePrivateKey(forAddress: wallet.address)
            let messageData = Data(message.utf8)
            let signature = try cryptoService.signMessage(messageData, privateKeyData: privateKeyData)
            return signature
        } catch {
            self.error = error.localizedDescription
            return nil
        }
    }
    
    func checkTransactionStatus(_ transaction: Transaction) async {
        guard let hash = transaction.hash else { return }
        
        do {
            if let receipt = try await blockchainService.getTransactionReceipt(txHash: hash) {
                if let index = transactions.firstIndex(where: { $0.id == transaction.id }) {
                    let updatedTx = Transaction(
                        id: transaction.id,
                        from: transaction.from,
                        to: transaction.to,
                        valueWei: transaction.valueWei,
                        gasPrice: transaction.gasPrice,
                        gasLimit: transaction.gasLimit,
                        nonce: transaction.nonce,
                        chainId: transaction.chainId,
                        hash: transaction.hash,
                        timestamp: transaction.timestamp,
                        status: receipt.isSuccess ? .confirmed : .failed
                    )
                    transactions[index] = updatedTx
                    saveTransactions()
                }
            }
        } catch {
            // Transaction may still be pending
        }
    }
    
    // MARK: - Persistence
    
    private func saveWallets() {
        if let data = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(data, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        if let data = UserDefaults.standard.data(forKey: walletsKey),
           let decoded = try? JSONDecoder().decode([Wallet].self, from: data) {
            wallets = decoded
            selectedWallet = decoded.first
        }
    }
    
    private func saveTransactions() {
        if let data = try? JSONEncoder().encode(transactions) {
            UserDefaults.standard.set(data, forKey: transactionsKey)
        }
    }
    
    private func loadTransactions() {
        if let data = UserDefaults.standard.data(forKey: transactionsKey),
           let decoded = try? JSONDecoder().decode([Transaction].self, from: data) {
            transactions = decoded
        }
    }
    
    func clearMnemonic() {
        mnemonic = nil
    }
    
    enum WalletError: LocalizedError {
        case invalidPrivateKey
        case noWalletSelected
        
        var errorDescription: String? {
            switch self {
            case .invalidPrivateKey: return "Invalid private key format"
            case .noWalletSelected: return "No wallet selected"
            }
        }
    }
}

