// MARK: - Views/ImportWalletView.swift

struct ImportWalletView: View {
    @EnvironmentObject var walletManager: WalletManager
    @Environment(\.dismiss) var dismiss
    @State private var walletName = ""
    @State private var mnemonicText = ""
    @State private var privateKeyText = ""
    @State private var importMethod = 0
    
    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Name") {
                    TextField("Name", text: $walletName)
                }
                
                Picker("Import Method", selection: $importMethod) {
                    Text("Recovery Phrase").tag(0)
                    Text("Private Key").tag(1)
                }
                .pickerStyle(.segmented)
                .padding(.vertical)
                
                if importMethod == 0 {
                    Section("Recovery Phrase") {
                        TextEditor(text: $mnemonicText)
                            .frame(minHeight: 100)
                            .font(.system(.body, design: .monospaced))
                        
                        Text("Enter your 12-word recovery phrase separated by spaces")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                } else {
                    Section("Private Key") {
                        SecureField("Enter private key", text: $privateKeyText)
                            .font(.system(.body, design: .monospaced))
                        
                        Text("Enter your private key (with or without 0x prefix)")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                
                Section {
                    Button("Import Wallet") {
                        Task {
                            let name = walletName.isEmpty ? "Imported Wallet" : walletName
                            if importMethod == 0 {
                                let words = mnemonicText
                                    .trimmingCharacters(in: .whitespacesAndNewlines)
                                    .components(separatedBy: .whitespaces)
                                    .filter { !$0.isEmpty }
                                await walletManager.importWallet(mnemonic: words, name: name)
                            } else {
                                await walletManager.importWalletFromPrivateKey(
                                    privateKeyText.trimmingCharacters(in: .whitespacesAndNewlines),
                                    name: name
                                )
                            }
                            if walletManager.error == nil {
                                dismiss()
                            }
                        }
                    }
                    .disabled(walletManager.isLoading)
                }
                
                if walletManager.isLoading {
                    Section {
                        HStack {
                            Spacer()
                            ProgressView()
                            Spacer()
                        }
                    }
                }
                
                if let error = walletManager.error {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle("Import Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
}

