// MARK: - Views/SendView.swift

struct SendView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var recipientAddress = ""
    @State private var amount = ""
    @State private var showConfirmation = false
    @State private var txHash: String?
    @State private var showResult = false
    
    var body: some View {
        NavigationView {
            Form {
                Section("From") {
                    if let wallet = walletManager.selectedWallet {
                        VStack(alignment: .leading, spacing: 4) {
                            Text(wallet.name)
                                .fontWeight(.semibold)
                            Text(wallet.address.truncatedAddress)
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Text("\(String(format: "%.6f", wallet.balanceETH)) ETH available")
                                .font(.caption)
                                .foregroundColor(.blue)
                        }
                    }
                }
                
                Section("To") {
                    TextField("Recipient Address (0x...)", text: $recipientAddress)
                        .font(.system(.body, design: .monospaced))
                        .autocapitalization(.none)
                        .autocorrectionDisabled()
                }
                
                Section("Amount") {
                    HStack {
                        TextField("0.0", text: $amount)
                            .keyboardType(.decimalPad)
                        Text("ETH")
                            .foregroundColor(.secondary)
                    }
                    
                    if let amountDouble = Double(amount), amountDouble > 0 {
                        Text("≈ $\(String(format: "%.2f", amountDouble * 2000)) USD")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                
                Section {
                    Button("Review Transaction") {
                        showConfirmation = true
                    }
                    .disabled(!isValidTransaction)
                    .frame(maxWidth: .infinity, alignment: .center)
                }
                
                if walletManager.isLoading {
                    Section {
                        HStack {
                            Spacer()
                            ProgressView("Sending...")
                            Spacer()
                        }
                    }
                }
                
                if let error = walletManager.error {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle("Send")
            .alert("Confirm Transaction", isPresented: $showConfirmation) {
                Button("Cancel", role: .cancel) {}
                Button("Send") {
                    Task {
                        guard let amountDouble = Double(amount) else { return }
                        txHash = await walletManager.sendTransaction(
                            to: recipientAddress,
                            amountETH: amountDouble
                        )
                        if txHash != nil {
                            showResult = true
                            recipientAddress = ""
                            amount = ""
                        }
                    }
                }
            } message: {
                Text("Send \(amount) ETH to \(recipientAddress.truncatedAddress)?")
            }
            .alert("Transaction Sent!", isPresented: $showResult) {
                Button("OK") {}
            } message: {
                if let hash = txHash {
                    Text("Transaction hash:\n\(hash)")
                }
            }
        }
    }
    
    private var isValidTransaction: Bool {
        guard !recipientAddress.isEmpty,
              recipientAddress.hasPrefix("0x"),
              recipientAddress.count == 42,
              let amountDouble = Double(amount),
              amountDouble > 0,
              !walletManager.isLoading else {
            return false
        }
        return true
    }
}

