import CoreImage.CIFilterBuiltins

struct ReceiveView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var hasCopied = false
    
    var body: some View {
        NavigationView {
            VStack(spacing: 24) {
                if let wallet = walletManager.selectedWallet {
                    Spacer()
                    
                    Text(wallet.name)
                        .font(.headline)
                    
                    // QR Code
                    if let qrImage = generateQRCode(from: wallet.address) {
                        Image(uiImage: qrImage)
                            .interpolation(.none)
                            .resizable()
                            .scaledToFit()
                            .frame(width: 200, height: 200)
                            .padding()
                            .background(Color.white)
                            .cornerRadius(16)
                            .shadow(radius: 5)
                    }
                    
                    // Address
                    VStack(spacing: 8) {
                        Text("Your Address")
                            .font(.caption)
                            .foregroundColor(.secondary)
                        
                        Text(wallet.address)
                            .font(.system(.caption, design: .monospaced))
                            .multilineTextAlignment(.center)
                            .padding()
                            .background(Color.secondary.opacity(0.1))
                            .cornerRadius(8)
                    }
                    .padding(.horizontal)
                    
                    Button(action: {
                        UIPasteboard.general.string = wallet.address
                        hasCopied = true
                        DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
                            hasCopied = false
                        }
                    }) {
                        HStack {
                            Image(systemName: hasCopied ? "checkmark.circle.fill" : "doc.on.doc")
                            Text(hasCopied ? "Copied!" : "Copy Address")
                        }
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(12)
                    }
                    .padding(.horizontal, 24)
                    
                    Button(action: shareAddress) {
                        HStack {
                            Image(systemName: "square.and.arrow.up")
                            Text("Share")
                        }
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.secondary.opacity(0.2))
                        .foregroundColor(.primary)
                        .cornerRadius(12)
                    }
                    .padding(.horizontal, 24)
                    
                    Spacer()
                } else {
                    Text("No wallet selected")
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle("Receive")
        }
    }
    
    private func generateQRCode(from string: String) -> UIImage? {
        let context = CIContext()
        let filter = CIFilter.qrCodeGenerator()
        
        filter.message = Data(string.utf8)
        filter.correctionLevel = "M"
        
        guard let outputImage = filter.outputImage else { return nil }
        
        let transform = CGAffineTransform(scaleX: 10, y: 10)
        let scaledImage = outputImage.transformed(by: transform)
        
        guard let cgImage = context.createCGImage(scaledImage, from: scaledImage.extent) else { return nil }
        
        return UIImage(cgImage: cgImage)
    }
    
    private func shareAddress() {
        guard let wallet = walletManager.selectedWallet else { return }
        let activityController = UIActivityViewController(
            activityItems: [wallet.address],
            applicationActivities: nil
        )
        
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let rootVC = windowScene.windows.first?.rootViewController {
            rootVC.present(activityController, animated: true)
        }
    }
}

