struct TransactionRowView: View {
    let transaction: Transaction
    
    var body: some View {
        HStack {
            Circle()
                .fill(statusColor)
                .frame(width: 10, height: 10)
            
            VStack(alignment: .leading, spacing: 2) {
                Text("To: \(transaction.to.truncatedAddress)")
                    .font(.caption)
                    .fontWeight(.medium)
                Text(transaction.timestamp, style: .relative)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            Text(formattedValue)
                .font(.caption)
                .fontWeight(.semibold)
                .foregroundColor(.red)
        }
        .padding(.horizontal)
        .padding(.vertical, 8)
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .pending: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }
    
    private var formattedValue: String {
        guard let wei = Double(transaction.valueWei) else { return "0 ETH" }
        let eth = wei / 1_000_000_000_000_000_000
        return String(format: "-%.6f ETH", eth)
    }
}

struct TransactionDetailRow: View {
    let transaction: Transaction
    
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Image(systemName: "arrow.up.circle.fill")
                    .foregroundColor(.red)
                
                VStack(alignment: .leading, spacing: 2) {
                    Text("Sent ETH")
                        .fontWeight(.semibold)
                    Text("To: \(transaction.to.truncatedAddress)")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                
                Spacer()
                
                VStack(alignment: .trailing, spacing: 2) {
                    Text(formattedValue)
                        .fontWeight(.semibold)
                        .foregroundColor(.red)
                    
                    StatusBadge(status: transaction.status)
                }
            }
            
            if let hash = transaction.hash {
                Text("Tx: \(hash.truncatedAddress)")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Text(transaction.timestamp, style: .date)
                .font(.caption2)
                .foregroundColor(.secondary)
        }
        .padding(.vertical, 4)
    }
    
    private var formattedValue: String {
        guard let wei = Double(transaction.valueWei) else { return "0 ETH" }
        let eth = wei / 1_000_000_000_000_000_000
        return String(format: "-%.6f ETH", eth)
    }
}

struct StatusBadge: View {
    let status: Transaction.TransactionStatus
    
    var body: some View {
        Text(status.rawValue.capitalized)
            .font(.caption2)
            .fontWeight(.medium)
            .padding(.horizontal, 8)
            .padding(.vertical, 2)
            .background(backgroundColor.opacity(0.2))
            .foregroundColor(backgroundColor)
            .cornerRadius(4)
    }
    
    private var backgroundColor: Color {
        switch status {
        case .pending: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }
}

